-- Ghana Tertiary UniConnect Dataset - part 6
-- Run parts sequentially in Supabase SQL Editor.

insert into public.departments (source_id, university_id, faculty_id, name) select 'upsa_computing_and_information_technology_software_engineering', u.id, f.id, 'Software Engineering' from public.universities u join public.faculties f on f.source_id = 'upsa_computing_and_information_technology' where u.source_id = 'upsa' and not exists (select 1 from public.departments where source_id = 'upsa_computing_and_information_technology_software_engineering' or (university_id = u.id and name = 'Software Engineering'));
update public.departments set source_id = coalesce(source_id, 'upsa_computing_and_information_technology_software_engineering'), faculty_id = (select id from public.faculties where source_id = 'upsa_computing_and_information_technology') where source_id = 'upsa_computing_and_information_technology_software_engineering' or (name = 'Software Engineering' and university_id = (select id from public.universities where source_id = 'upsa'));
