update public.departments set source_id = coalesce(source_id, 'sdd_ubids_computing_and_information_technology_software_engineering'), faculty_id = (select id from public.faculties where source_id = 'sdd_ubids_computing_and_information_technology') where source_id = 'sdd_ubids_computing_and_information_technology_software_engineering' or (name = 'Software Engineering' and university_id = (select id from public.universities where source_id = 'sdd_ubids'));
